import pytest

def test_invalid_sso_assertion_is_rejected(api_client, invalid_sso_assertion):
    payload = {"sso_assertion": invalid_sso_assertion}
    resp = api_client.post("/portal/login", json=payload)
    assert resp.status_code == 401, f"Expected 401, got {resp.status_code}"
    body = resp.json()
    assert body.get("error") == "sso_assertion_invalid", (
        f"Unexpected error value: {body.get('error')}"
    )
    assert "session_token" not in body, "session_token must not be issued on failure"
